#include <bits/stdc++.h>
using namespace std;
int a,b,g[502][502],v[502];
void Prim(){
    int tot=1,ans=a;
    v[1]=1;
    while(tot<b){
    	int x=-1,w=0;
    	for(int i=1;i<=b;i++){
    		if(!v[i])continue;
    		for(int j=1;j<=b;j++)
    			if(!v[j] && (x==-1 || x>g[i][j]))x=g[i][j],w=j;
		}
		ans+=x,tot++,v[w]=1;
	}
	cout<<ans;
}
int main(){
    cin>>a>>b;
    for(int i=1;i<=b;i++)
        for(int j=1;j<=b;j++){
            cin>>g[i][j];
            if(g[i][j]==0 || g[i][j]>a)g[i][j]=a;
        }
    Prim();
    return 0;
}
